import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { ConfirmModalComponent } from '../../../core/components/confirm-modal/confirm-modal.component';
import { ToastService } from '../../../core/services/toast.service';
import { getSubscriptionClass } from '../../../core/utils/subscription.utils';
import { DocenteRequest, DocenteResponse } from '../../../core/models/docente.model';
import { DocenteService } from '../../../core/services/docente.service';

@Component({
  selector: 'app-docentes',
  standalone: true,
  imports: [CommonModule, FormsModule, ReactiveFormsModule, ConfirmModalComponent],
  templateUrl: './docentes.component.html',
  styleUrls: ['./docentes.component.css']
})
export class DocentesComponent implements OnInit {
  private docenteService = inject(DocenteService);
  private fb = inject(FormBuilder);
  private toastService = inject(ToastService);

  docentes: DocenteResponse[] = [];
  filteredDocentes: DocenteResponse[] = [];
  searchQuery = '';
  dateSortOrder: 'desc' | 'asc' = 'desc';
  currentPage = 1;
  readonly pageSize = 10;
  totalElements = 0;

  showCreateEditModal = false;
  isEditMode = false;
  isFormSubmitting = false;
  modalErrorMsg = '';
  showConfirmModal = false;
  confirmModalType: 'success' | 'danger' | 'info' | 'warning' = 'warning';
  confirmModalTitle = '';
  confirmModalMessage = '';
  pendingAction: (() => void) | null = null;
  selectedDocente: DocenteResponse | null = null;

  docenteForm: FormGroup = this.fb.group({
    nombres: ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100)]],
    apellidos: ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100)]],
    correo: ['', [Validators.required, Validators.email, Validators.maxLength(150)]],
    telefono: [''],
    nivelSuscripcionId: [1, [Validators.required]],
    password: ['', [Validators.minLength(6)]],
    estado: [true]
  });

  ngOnInit(): void { this.loadDocentes(); }

  loadDocentes(): void {
    this.docenteService.listarDocentes(this.currentPage - 1, this.pageSize, this.searchQuery).subscribe({
      next: (res) => {
        this.docentes = Array.isArray(res) ? res : (res?.content ?? []);
        this.totalElements = Array.isArray(res) ? this.docentes.length : (res?.totalElements ?? this.docentes.length);
        this.applyFilter();
      },
      error: (err) => console.error('Error al listar docentes', err)
    });
  }

  applyFilter(): void {
    const query = this.searchQuery.trim().toLowerCase();
    this.filteredDocentes = this.docentes.filter(d =>
      !query || d.nombres.toLowerCase().includes(query) || d.apellidos.toLowerCase().includes(query) || d.correo.toLowerCase().includes(query)
    ).sort((a, b) => {
      const d1 = new Date(a.fechaRegistro).getTime() || 0;
      const d2 = new Date(b.fechaRegistro).getTime() || 0;
      return this.dateSortOrder === 'asc' ? d1 - d2 : d2 - d1;
    });
  }

  onSearchChange(): void { this.currentPage = 1; this.loadDocentes(); }
  onDateSortChange(order: string): void { this.dateSortOrder = order === 'asc' ? 'asc' : 'desc'; this.applyFilter(); }
  get totalPages(): number { return Math.max(1, Math.ceil(this.filteredDocentes.length / this.pageSize)); }
  get paginatedDocentes(): AlumnoResponse[] { const start = (this.currentPage - 1) * this.pageSize; return this.filteredDocentes.slice(start, start + this.pageSize); }
  goToPage(page: number): void { if (page < 1 || page > this.totalPages) return; this.currentPage = page; }

  openCreateModal(): void {
    this.isEditMode = false; this.modalErrorMsg = ''; this.selectedDocente = null;
    this.docenteForm.reset({ nombres: '', apellidos: '', correo: '', telefono: '', nivelSuscripcionId: 1, estado: true });
    this.showCreateEditModal = true;
  }
  openEditModal(docente: AlumnoResponse): void {
    this.isEditMode = true; this.modalErrorMsg = ''; this.selectedDocente = docente;
    this.docenteForm.patchValue({ nombres: docente.nombres, apellidos: docente.apellidos, correo: docente.correo, telefono: docente.telefono, nivelSuscripcionId: 1, estado: docente.estado });
    this.showCreateEditModal = true;
  }
  closeCreateEditModal(): void { this.showCreateEditModal = false; this.isFormSubmitting = false; }
  toggleEstado(docente: AlumnoResponse): void {
    const nuevoEstado = !docente.estado;
    this.confirmModalType = nuevoEstado ? 'success' : 'danger';
    this.confirmModalTitle = `¿${nuevoEstado ? 'Activar' : 'Desactivar'} Docente?`;
    this.confirmModalMessage = `¿Deseas ${nuevoEstado ? 'activar' : 'desactivar'} a ${docente.nombres} ${docente.apellidos}?`;
    this.pendingAction = () => this.docenteService.cambiarEstado(docente.id, nuevoEstado).subscribe({
      next: () => { docente.estado = nuevoEstado; this.toastService.success(`Docente ${nuevoEstado ? 'activado' : 'desactivado'} exitosamente.`); this.showConfirmModal = false; },
      error: (err) => { this.toastService.error(err.error?.message || 'Error al cambiar el estado del docente.'); this.showConfirmModal = false; }
    });
    this.showConfirmModal = true;
  }
  confirmAction(): void { this.pendingAction?.(); }
  onSubmit(): void {
    if (this.docenteForm.invalid) { this.docenteForm.markAllAsTouched(); return; }
    const req: DocenteRequest = { nombres: this.docenteForm.value.nombres, apellidos: this.docenteForm.value.apellidos, correo: this.docenteForm.value.correo, telefono: this.docenteForm.value.telefono || '', password: this.docenteForm.value.password || undefined };
    this.isFormSubmitting = true;
    const call$ = this.isEditMode && this.selectedDocente ? this.docenteService.editarDocente(this.selectedDocente.id, req) : this.docenteService.crearDocente(req);
    call$.subscribe({
      next: () => { this.loadDocentes(); this.toastService.success(this.isEditMode ? 'Docente actualizado exitosamente.' : 'Docente registrado exitosamente.'); this.closeCreateEditModal(); },
      error: (err) => { this.isFormSubmitting = false; this.modalErrorMsg = err.error?.message || 'Error al procesar la solicitud.'; this.toastService.error(this.modalErrorMsg, 'Error en el Servidor'); }
    });
  }

  getSubscriptionClass = getSubscriptionClass;
}
<div class="space-y-6">
  <section class="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-6">
    <div class="flex flex-col lg:flex-row lg:items-end lg:justify-between gap-4">
      <div>
        <p class="text-xs font-black uppercase tracking-[0.35em] text-primary">Administración</p>
        <h1 class="text-2xl font-black uppercase text-slate-900 dark:text-white mt-2">Docentes</h1>
        <p class="text-sm text-slate-500 dark:text-slate-400 mt-1">Crear, editar, listar y desactivar docentes de la plataforma.</p>
      </div>
      <div class="flex gap-3">
        <button (click)="openCreateModal()" class="px-5 py-3 bg-primary text-white text-xs font-black uppercase tracking-widest">Nuevo docente</button>
      </div>
    </div>
    <div class="grid grid-cols-1 md:grid-cols-3 gap-3 mt-6">
      <input [(ngModel)]="searchQuery" (input)="onSearchChange()" placeholder="Buscar por nombre, correo..." class="border px-4 py-3 bg-slate-50 dark:bg-slate-950" />
      <select [ngModel]="dateSortOrder" (ngModelChange)="onDateSortChange($event)" class="border px-4 py-3 bg-slate-50 dark:bg-slate-950">
        <option value="desc">Fecha descendente</option>
        <option value="asc">Fecha ascendente</option>
      </select>
      <div class="text-sm text-slate-500 self-center">{{ filteredDocentes.length }} docentes</div>
    </div>
  </section>

  <section class="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 overflow-hidden">
    <table class="w-full text-left">
      <thead><tr class="text-xs uppercase tracking-widest text-slate-500"><th class="p-4">Nombre</th><th class="p-4">Correo</th><th class="p-4">Fecha</th><th class="p-4">Estado</th><th class="p-4">Acciones</th></tr></thead>
      <tbody>
        <tr *ngFor="let docente of paginatedDocentes">
          <td class="p-4">{{ docente.nombres }} {{ docente.apellidos }}</td>
          <td class="p-4">{{ docente.correo }}</td>
          <td class="p-4">{{ docente.fechaRegistro | date:'dd/MM/yyyy HH:mm' }}</td>
          <td class="p-4"><span [class]="docente.estado ? 'text-emerald-600' : 'text-red-600'">{{ docente.estado ? 'Activo' : 'Inactivo' }}</span></td>
          <td class="p-4 space-x-2">
            <button (click)="openEditModal(docente)" class="border px-3 py-2 text-xs">Editar</button>
            <button (click)="toggleEstado(docente)" class="border px-3 py-2 text-xs">{{ docente.estado ? 'Desactivar' : 'Activar' }}</button>
          </td>
        </tr>
      </tbody>
    </table>
  </section>

  <div *ngIf="totalPages > 1" class="flex justify-between items-center">
    <button (click)="goToPage(currentPage - 1)" [disabled]="currentPage===1" class="border px-4 py-2">Anterior</button>
    <span class="text-sm">Página {{ currentPage }} de {{ totalPages }}</span>
    <button (click)="goToPage(currentPage + 1)" [disabled]="currentPage===totalPages" class="border px-4 py-2">Siguiente</button>
  </div>

  <app-confirm-modal *ngIf="showConfirmModal" [type]="confirmModalType" [title]="confirmModalTitle" [message]="confirmModalMessage" (confirm)="confirmAction()" (cancel)="showConfirmModal=false"></app-confirm-modal>
</div>
